        <div className="app">
          <header className="app-header">
            <h1>Стоматологические тесты</h1>
          </header>
          <main>
            <Routes>
              <Route path="/" element={<QuizSelectionPage />} />
              <Route path="/quiz/:quizId" element={<QuizPage quizData={quizData} />} />
            </Routes>
          </main>
