// Component to load the appropriate quiz based on URL parameter
const QuizPage = ({ quizData }) => {
  const { quizId } = useParams();
  const navigate = useNavigate();

    // Redirect to home if quiz doesn't exist
  if (!quizData[quizId]) {
    useEffect(() => {

      navigate('/');
    }, [navigate]);
    return <div>Загрузка...</div>;
  }

  return (
      <div>
        <h2>{quizData[quizId].title}</h2>
        <button className="back-button" onClick={() => navigate('/')}>
          ← Назад к выбору тестов
        </button>
        <QuizApp questions={quizData[quizId].questions} />
      </div>
  );
};

export default App;
